SELECT * FROM sys_log


        AND username LIKE CONCAT('%', #{username}, '%')


        AND operation LIKE CONCAT('%', #{operation}, '%')


        AND module = #{module}


        AND ip = #{ip}


        AND create_time >= #{startTime}


        AND create_time <= #{endTime}


        AND status_code = #{statusCode}


        AND method = #{method}


        AND uri LIKE CONCAT('%', #{uri}, '%')


